const express = require('express');
const { Pool } = require('pg');

const app = express();

app.use(express.json());

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'my_database',
  password: 'password',
  port: 5432,
});

app.post('/api/data', (req, res) => {
  const {table, where} = req.body;
  pool.query(`INSERT INTO ${table} VALUES (${where})`, (error, results) => {
    if (error) {
      throw error
    }
    res.status(201).send(`Data added with ID: ${results.insertId}`)
  })
});

app.get('/api/data/:table', (req, res) => {
  pool.query('SELECT * FROM ' + req.params.table, (error, results) => {
    if (error) {
      throw error
    }
    res.status(200).json(results.rows)
  })
});

app.put('/api/data/:table', (req, res) => {
  const id = parseInt(req.params.id)
  const {table, set, where} = req.body;
  pool.query(`UPDATE ${table} SET ${set} WHERE ${where}`, (error, results) => {
    if (error) {
      throw error
    }
    res.status(200).send(`Data modified with ID: ${id}`)
  })
});

app.delete('/api/data/:table/:id', (req, res) => {
  const id = parseInt(req.params.id)

  pool.query(`DELETE FROM ${req.params.table} WHERE id = ${id}`, (error, results) => {
    if (error) {
      throw error
    }
    res.status(200).send(`Data deleted with ID: ${id}`)
  })
});

app.listen(3000, () => {
  console.log('Server is running.. on Port 3000');
});